"use strict";(self.webpackChunkresoluteraccoon_website=self.webpackChunkresoluteraccoon_website||[]).push([["6607"],{7735(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome-to-resolute-raccoon","metadata":{"permalink":"/blog/welcome-to-resolute-raccoon","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2025-01-07-welcome.md","source":"@site/blog/2025-01-07-welcome.md","title":"Welcome to Resolute Raccoon","description":"We\'re a community of elite student builders from Ozoro, Nigeria. We focus on:","date":"2025-01-07T00:00:00.000Z","tags":[{"inline":true,"label":"announcement","permalink":"/blog/tags/announcement"},{"inline":true,"label":"community","permalink":"/blog/tags/community"}],"readingTime":0.82,"hasTruncateMarker":false,"authors":[{"name":"Miracle Omokaro","title":"Founder, Resolute Raccoon | Cybersecurity @ SDU","url":"https://github.com/miracleomokaro","page":{"permalink":"/blog/authors/miracleomokaro"},"socials":{"x":"https://x.com/miracleomokaro","github":"https://github.com/miracleomokaro","linkedin":"https://www.linkedin.com/in/miracle-omokaro/"},"imageURL":"https://github.com/miracleomokaro.png","key":"miracleomokaro"}],"frontMatter":{"slug":"welcome-to-resolute-raccoon","title":"Welcome to Resolute Raccoon","authors":["miracleomokaro"],"tags":["announcement","community"],"date":"2025-01-07T00:00:00.000Z"},"unlisted":false},"content":"We\'re a community of elite student builders from Ozoro, Nigeria. We focus on:\\n\\n- **Cybersecurity** \u2014 Offensive, defensive, CTFs, bug bounties\\n- **Systems Engineering** \u2014 C/C++, Linux kernel, networking, distributed systems\\n- **AI/ML Engineering** \u2014 LLM ops, agentic systems, computer vision, MLOps\\n\\n## What Makes Us Different\\n\\n**No tutorials. Just work.**\\n\\nWe curate the best free platforms (pwn.college, TryHackMe, PortSwigger, CSAPP, Fast.ai) into locked progression paths. You don\'t advance until you prove it. No one gets left behind, and no one skips ahead.\\n\\n**Community over content.**\\n\\nDiscord for daily comms. Weekly syncs every Sunday 7 PM WAT. Quarterly 48-hour hackathons. Bi-weekly movie nights with technical breakdowns. Readers Club for technical + human breadth.\\n\\n**Ship or it didn\'t happen.**\\n\\nEvery member ships projects to GitHub. Our Hopper incubator runs 6-week cycles: Pitch \u2192 Spec \u2192 Build \u2192 Review \u2192 Ship \u2192 Retro.\\n\\n## Join Us\\n\\n- **Discord:** [discord.gg/resoluteraccoon](https://discord.gg/resoluteraccoon)\\n- **GitHub:** [github.com/resoluteraccoon](https://github.com/resoluteraccoon)\\n- **Newsletter:** [buttondown.email/resoluteraccoon](https://buttondown.email/resoluteraccoon)\\n\\nIf you\'re ready to stop playing small, you\'re one of us."}]}}')}}]);